from vex_sdk import VexClient, Schema

vex = VexClient(api_key='vex-key')

hr_schema = Schema({
    'type': 'object',
    'properties': {
        'candidate_score': {'type': 'number', 'maximum': 100},
        'reasoning': {
            'type': 'string',
            'not_contains': ['age', 'gender', 'race', 'PTA', 'veteran'],
            'pattern': '.*(EEOC|non-discrimination).*'
        },
        'disclosure': {'const': 'This screening uses AI per NYC LL144'}
    },
    'required': ['disclosure'],
    'risk_keywords': ['discriminate', 'cultural fit']
})

schema_id = vex.schemas.create('hr-screening-compliance', hr_schema)

import { Vex } from '@vex/sdk';
import { OpenAI } from 'openai';

const vex = new Vex({ apiKey: process.env.VEX_KEY });
const openai = new OpenAI({ apiKey: process.env.OPENAI_KEY });

export async function POST(request: Request) {
  const event = await request.json();

  if (event.event === 'thread.run.completed') {
    const run = await openai.beta.threads.runs.retrieve(
      event.data.thread_id,
      event.data.id
    );

    const result = await vex.verify({
      schemaId: 'hr-screening-compliance',
      input: run.required_action?.submit_tool_outputs?.tool_outputs || run.last_message?.content
    });

    if (!result.valid) {
      // Block discriminatory output
      await openai.beta.threads.runs.submit_tool_outputs(
        event.data.thread_id,
        event.data.id,
        {
          tool_outputs: [{ tool_call_id: 'block', output: 'Compliance violation detected' }]
        }
      );
    }
  }

  return new Response('OK');
}
